import openai

openai.api_key = "<KEY>"

def chatbot(message):
    response = openai.ChatCompletion.create(
        model="gpt-3.5-turbo",
        messages=[
            {"role": "user", "content": message},
        ],
        max_tokens=10,
    )

    return response["choices"][0]["message"]["content"]

